// === DETECTAR RESPUESTA SARA v4 - Deteccion Dual JID ===
// BOT messages come from @s.whatsapp.net, SARA+CLIENTE from @lid
const contactData = $('Juntar Resultados').first().json;
const senderName = contactData.senderName || '';
const combinedText = contactData.combinedText || '';
const hasAudio = contactData.hasAudio || false;
const hasImage = contactData.hasImage || false;
const audioTranscription = contactData.audioTranscription || '';
const imageAnalysis = contactData.imageAnalysis || '';
const messageCount = contactData.messageCount || 0;
const remoteJid = contactData.remoteJid || '';
// Info del LID
const lidInfo = $('Extraer LID').first().json;
const lidJid = lidInfo.lidJid || '';
const lidEncontrado = lidInfo.lidEncontrado || false;
// Obtener mensajes de ambas fuentes
const botRaw = $('Obtener Historial BOT').first().json;
const lidRaw = $('Obtener Historial LID').first().json;
// Extraer records de la estructura paginada
const botMessages = botRaw.messages?.records || botRaw.records || (Array.isArray(botRaw) ? botRaw : []);
const lidMessages = lidRaw.messages?.records || lidRaw.records || (Array.isArray(lidRaw) ? lidRaw : []);
// Construir timeline combinado
const timeline = [];
const seenKeys = new Set();
const ZWS = '\u200B';
// --- Mensajes BOT (@s.whatsapp.net) - todos fromMe=true, enviados por el bot ---
for (const m of botMessages) {
  const keyId = m.key?.id || '';
  if (keyId && seenKeys.has(keyId)) continue;
  if (keyId) seenKeys.add(keyId);
  const texto = m.message?.conversation
    || m.message?.extendedTextMessage?.text
    || m.message?.imageMessage?.caption
    || (m.message?.audioMessage ? '[AUDIO]' : null)
    || (m.message?.imageMessage ? '[IMAGEN]' : null)
    || '';
  if (!texto) continue;
  timeline.push({
    timestamp: m.messageTimestamp || 0,
    quien: 'BOT',
    texto: texto,
    fromMe: true
  });
}
// --- Mensajes LID (@lid) - fromMe=true son ZORAIDA humana, fromMe=false son CLIENTE ---
for (const m of lidMessages) {
  const keyId = m.key?.id || '';
  if (keyId && seenKeys.has(keyId)) continue;
  if (keyId) seenKeys.add(keyId);
  const isFromMe = m.key?.fromMe === true;
  const texto = m.message?.conversation
    || m.message?.extendedTextMessage?.text
    || m.message?.imageMessage?.caption
    || (m.message?.audioMessage ? '[AUDIO]' : null)
    || (m.message?.imageMessage ? '[IMAGEN]' : null)
    || '';
  if (!texto) continue;
  timeline.push({
    timestamp: m.messageTimestamp || 0,
    quien: isFromMe ? 'ZORAIDA' : 'CLIENTE',
    texto: texto,
    fromMe: isFromMe
  });
}
// Ordenar cronologicamente
timeline.sort((a, b) => a.timestamp - b.timestamp);
// Detectar si Sara respondio en los ultimos 7 dias
const ZORAIDA_WINDOW_MS = 7 * 24 * 60 * 60 * 1000;
const now = Date.now();
let saraReplied = false;
let lastSaraMessage = '';
let saraMessageCount = 0;
for (const m of timeline) {
  if (m.quien === 'ZORAIDA') {
    const msgAge = now - (m.timestamp * 1000);
    if (msgAge < ZORAIDA_WINDOW_MS) {
      saraReplied = true;
      lastSaraMessage = m.texto;
      saraMessageCount++;
    }
  }
}
// FALLBACK: Si no se encontro LID, usar metodo ZWS como respaldo
// (mensajes del bot tienen ZWS al inicio, mensajes de Sara humana no)
if (!lidEncontrado && !saraReplied) {
  for (const m of botMessages) {
    const isFromMe = m.key?.fromMe === true;
    const texto = m.message?.conversation
      || m.message?.extendedTextMessage?.text || '';
    const timestamp = (m.messageTimestamp || 0) * 1000;
    const isRecent = (now - timestamp) < ZORAIDA_WINDOW_MS;
    if (isFromMe && texto && !texto.startsWith(ZWS) && isRecent) {
      saraReplied = true;
      lastSaraMessage = texto;
      saraMessageCount++;
    }
  }
}
// Formatear historial para el LLM (ultimos 20 mensajes)
const formattedHistory = timeline.slice(-20).map(m => {
  // Para el LLM: BOT y ZORAIDA son "nuestro lado", CLIENTE es el cliente
  const label = m.quien === 'CLIENTE' ? 'Cliente' : (m.quien === 'ZORAIDA' ? 'Sara' : 'Bot');
  return label + ': ' + m.texto;
});
// Output: misma estructura que antes para compatibilidad con nodos downstream
return [{ json: {
  remoteJid,
  senderName,
  combinedText,
  hasAudio,
  hasImage,
  audioTranscription,
  imageAnalysis,
  saraReplied,
  lastSaraMessage,
  saraMessageCount,
  chatHistory: formattedHistory.join('\n'),
  messageCount,
  // Metadata extra (no rompe nada downstream)
  lidJid,
  lidEncontrado,
  totalMensajesBot: botMessages.length,
  totalMensajesLid: lidMessages.length
}}];

const contactData = $('Sara Ya Respondio?').first().json;
const remoteJid = contactData.remoteJid || '';
const senderName = contactData.senderName || '';
const combinedText = contactData.combinedText || '';
const hasAudio = contactData.hasAudio || false;
const hasImage = contactData.hasImage || false;

// Leer audioTranscription directamente de contactData (ya viene acumulado desde Juntar Resultados)
const audioTranscription = contactData.audioTranscription || '';

// FIX v3: Asegurar que imageAnalysis sea siempre un string legible
// Puede venir como string (correcto), array u objeto (incorrecto)
let imageAnalysisRaw = contactData.imageAnalysis || '';
let imageAnalysis = '';
if (typeof imageAnalysisRaw === 'string') {
  imageAnalysis = imageAnalysisRaw;
} else if (Array.isArray(imageAnalysisRaw)) {
  imageAnalysis = imageAnalysisRaw.map(a => {
    if (typeof a === 'string') return a;
    if (a && a.text) return a.text;
    if (a && a.content && Array.isArray(a.content)) return a.content.filter(c => c.type === 'text').map(c => c.text).join(' ');
    return JSON.stringify(a);
  }).join('\n');
} else if (typeof imageAnalysisRaw === 'object') {
  imageAnalysis = JSON.stringify(imageAnalysisRaw);
}
// Evitar el infame [object Object]
if (imageAnalysis === '[object Object]') imageAnalysis = '';

const chatHistory = contactData.chatHistory || '';
const messageCount = contactData.messageCount || 0;

let activeOrders = 'Sin pedidos activos';
try {
  const pedidosItems = $('Buscar Pedidos Activos').all();
  const found = pedidosItems
    .map(i => i.json)
    .filter(p => p && remoteJid && remoteJid.includes(p.telefono_cliente));
  if (found.length > 0) {
    activeOrders = found.map(p =>
      'Pedido: ' + (p.producto||'N/A') + ' | Estado: ' + (p.estado||'N/A') + ' | Entrega: ' + (p.fecha_entrega||'N/A')
    ).join('\n');
  }
} catch(e) { activeOrders = 'No se pudo consultar pedidos'; }

let catalogSummary = 'Catalogo no disponible';
try {
  const catItems = $('Cargar Catalogo').all();
  const disp = catItems
    .map(i => i.json)
    .filter(p => p && p.disponible !== 'no');
  if (disp.length > 0) {
    catalogSummary = disp.map(p =>
      '- ' + (p.nombre||'N/A') + ': ' + (p.precio||'N/A') + ' (' + (p.categoria||'general') + ') - ' + (p.descripcion||'') + ' | Tamaños: ' + (p['tamaños']||p.tamanos||'N/A') + ' | IMG: ' + (p.imagen_url||'sin imagen')
    ).join('\n');
  }
} catch(e) { catalogSummary = 'No se pudo cargar catalogo'; }

const now = new Date();
const fechaHora = now.toLocaleDateString('es-CO', {
  year:'numeric', month:'2-digit', day:'2-digit',
  hour:'2-digit', minute:'2-digit', timeZone:'America/Bogota'
});

return [{ json: {
  remoteJid, senderName, combinedText,
  hasAudio, hasImage, audioTranscription, imageAnalysis,
  saraReplied: contactData.saraReplied || false,
  chatHistory,
  hasActiveOrder: activeOrders !== 'Sin pedidos activos' && activeOrders !== 'No se pudo consultar pedidos',
  activeOrderDetails: activeOrders,
  catalogSummary,
  fechaHora,
  messageCount
}}];

const rawInput = $input.first().json;
const llmOutput = rawInput.text || rawInput.output || rawInput.response || '';
let remoteJid = '', senderName = '', clientText = '';
try {
  remoteJid = $('Consolidar Contexto').first().json.remoteJid || '';
  senderName = $('Consolidar Contexto').first().json.senderName || '';
  clientText = $('Consolidar Contexto').first().json.combinedText || '';
} catch(e) {}

// FIX v5: detectar errores explicitos del agente
const hasError = rawInput.error || rawInput.errorMessage ||
  (typeof llmOutput === 'string' && llmOutput.includes('service was not able'));

// FIX v5: detectar respuesta VACIA o sin JSON valido (caso del bug)
const cleanedOutput = (typeof llmOutput === 'string') ? llmOutput.trim() : '';
const looksEmpty = cleanedOutput.length < 5;

// Default fallback (solo se usa si nada mas funciona)
let parsed = {
  action: 'silent',
  messages: [],
  image_messages: [],
  escalate_reason: null,
  escalate_to: null,
  send_images: [],
  detected_intent: 'desconocido',
  notify_sara: false,
  sara_summary: '',
  register_lead: false,
  lead_data: {},
  pause_bot: false
};

// CASO ERROR EXPLICITO o RESPUESTA VACIA - escalar a Sara y avisar al cliente
if (hasError || looksEmpty) {
  const reasonDetail = hasError
    ? ('Error del agente: ' + (rawInput.error || rawInput.errorMessage || 'Error desconocido'))
    : 'El modelo devolvio respuesta vacia (sin output). Cliente envio: ' + (clientText || '[mensaje sin texto, posible solo imagen/audio]').substring(0, 250);
  parsed = {
    action: 'escalate',
    messages: ['Dame un momento, ya te respondo 😊'],
    image_messages: [],
    escalate_reason: 'FALLO_BOT - ' + reasonDetail,
    escalate_to: 'sara',
    send_images: [],
    detected_intent: 'error',
    notify_sara: true,
    sara_summary: 'FALLO BOT: el agente fallo procesando mensaje del cliente ' + remoteJid + '. Detalle: ' + reasonDetail,
    register_lead: false,
    lead_data: {},
    pause_bot: true
  };
} else {
  // Intentar parsear el JSON del output del LLM
  let parsedOk = false;
  try {
    const jsonMatch = cleanedOutput.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const c = JSON.parse(jsonMatch[0]);
      if (c.action && c.messages) {
        parsed = c;
        parsedOk = true;
      }
    }
  } catch(e) {
    // Si la respuesta del LLM es texto plano corto, lo enviamos tal cual
    if (cleanedOutput.length > 5 && cleanedOutput.length < 500) {
      parsed = {
        action: 'reply',
        messages: [cleanedOutput.replace(/`/g,'').trim()],
        image_messages: [],
        escalate_reason: null,
        escalate_to: null,
        send_images: [],
        detected_intent: 'desconocido',
        notify_sara: false,
        sara_summary: '',
        register_lead: false,
        lead_data: {},
        pause_bot: false
      };
      parsedOk = true;
    }
  }
  // Si no se pudo parsear, escalar a Sara (no enviamos respuesta default sin sentido)
  if (!parsedOk) {
    parsed = {
      action: 'escalate',
      messages: ['Dame un momento, ya te respondo 😊'],
      image_messages: [],
      escalate_reason: 'FALLO_BOT - El LLM devolvio output que no se pudo parsear como JSON. Output: ' + cleanedOutput.substring(0, 250),
      escalate_to: 'sara',
      send_images: [],
      detected_intent: 'error',
      notify_sara: true,
      sara_summary: 'FALLO BOT: output del LLM no parseable. Cliente: ' + remoteJid + '. Mensaje: ' + (clientText || '[sin texto]').substring(0, 200),
      register_lead: false,
      lead_data: {},
      pause_bot: true
    };
  }
}

if (!Array.isArray(parsed.messages)) parsed.messages = [String(parsed.messages)];
if (!Array.isArray(parsed.image_messages)) parsed.image_messages = [];
if (!Array.isArray(parsed.send_images)) parsed.send_images = [];
if (!['reply','escalate','silent'].includes(parsed.action)) parsed.action = 'reply';

return [{ json: {
  remoteJid,
  senderName,
  action: parsed.action,
  messages: parsed.messages,
  image_messages: parsed.image_messages,
  escalate_reason: parsed.escalate_reason || null,
  escalate_to: parsed.escalate_to || null,
  send_images: parsed.send_images || [],
  detected_intent: parsed.detected_intent || 'desconocido',
  notify_sara: parsed.notify_sara || false,
  sara_summary: parsed.sara_summary || '',
  register_lead: parsed.register_lead || false,
  lead_data: parsed.lead_data || {},
  pause_bot: parsed.pause_bot || false
}}];

const EVOLUTION_URL = $env.PROD_EVOLUTION_API_URL;
const EVOLUTION_KEY = $env.PROD_detalles_floristeria_barranquilla_EVOLUTION_API_KEY;
const INSTANCE = $env.PROD_detalles_floristeria_barranquilla_EVOLUTION_INSTANCE;
const SARA_PHONE = $env.PROD_detalles_floristeria_barranquilla_Sara_PHONE;

const errorMsg = $json.execution?.error?.message || $json.error?.message || 'Error desconocido';
const workflowName = $json.workflow?.name || 'Floristeria Detalles Bot';

try {
  await $helpers.httpRequest({
    method: 'POST',
    url: EVOLUTION_URL + '/message/sendText/' + INSTANCE,
    headers: { 'apikey': EVOLUTION_KEY, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      number: SARA_PHONE,
      text: '\u274c ERROR BOT FLORISTERIA DETALLES\n\nWorkflow: ' + workflowName + '\nError: ' + String(errorMsg).substring(0, 500)
    })
  });
} catch(e) {}

return [{ json: { notified: true, error: errorMsg } }];

const ZWS = '\u200B';
const data = $input.first().json;
const messages = data.messages || [];
const remoteJid = data.remoteJid;

if (messages.length === 0) {
  return [{ json: { remoteJid, text: '', empty: true } }];
}

return messages.map(msg => ({
  json: {
    remoteJid,
    text: ZWS + msg
  }
}));

const data = $input.first().json;
const images = data.send_images || [];
const remoteJid = data.remoteJid;

if (images.length === 0) {
  return [{ json: { remoteJid, imageUrl: '', empty: true } }];
}

return images.map(url => ({
  json: {
    remoteJid,
    imageUrl: url
  }
}));

const input = $input.first().json;
const mediaData = input.data;
const base64 = mediaData.base64 || '';
const mimetype = mediaData.mimetype || 'image/jpeg';

const binaryData = Buffer.from(base64, 'base64');

return [{
  json: {
    ...mediaData
  },
  binary: {
    image: {
      data: base64,
      mimeType: mimetype,
      fileName: mediaData.fileName || 'image.jpg'
    }
  }
}];

const input = $('Parsear chatInput').first().json;
return [{
  json: {
    remoteJid: input.remoteJid,
    senderName: input.senderName,
    combinedText: input.combinedText || '',
    messageCount: input.messageCount,
    hasImage: input.hasImage || false,
    hasAudio: input.hasAudio || false,
    imageMessageId: input.imageMessageId || '',
    audioMessageId: input.audioMessageId || '',
    audioMessageIds: input.audioMessageIds || [],
    imageMessageIds: input.imageMessageIds || []
  }
}];

const execId = $execution.id;
const staticData = $getWorkflowStaticData('global');
const infoData = $('Info Multimedia').first().json;

const audioKey = 'audio_' + execId;
const imageKey = 'image_' + execId;
const audioTranscription = (staticData[audioKey] || []).join('\n');
const imageAnalysis = (staticData[imageKey] || []).join('\n');

// Cleanup static data for this execution
delete staticData[audioKey];
delete staticData[imageKey];

return [{
  json: {
    remoteJid: infoData.remoteJid,
    senderName: infoData.senderName,
    combinedText: infoData.combinedText,
    messageCount: infoData.messageCount,
    hasAudio: infoData.hasAudio,
    hasImage: infoData.hasImage,
    audioTranscription: audioTranscription,
    imageAnalysis: imageAnalysis
  }
}];

const input = $input.first().json;
const mediaData = input.data;
const base64 = mediaData.base64 || '';
const mimetype = mediaData.mimetype || 'audio/ogg';

return [{
  json: {
    ...mediaData
  },
  binary: {
    data: {
      data: base64,
      mimeType: mimetype,
      fileName: mediaData.fileName || 'audio.ogg'
    }
  }
}];

const data = $input.first().json;
const imageMessages = data.image_messages || [];
const remoteJid = data.remoteJid;

if (imageMessages.length === 0) {
  return [{ json: { remoteJid, imageUrl: '', caption: '', empty: true } }];
}

return imageMessages.map(item => ({
  json: {
    remoteJid,
    imageUrl: item.image,
    caption: item.caption || ''
  }
}));

const data = $input.first().json;
const pausado = data.pausado;
const fechaPausa = data.fecha_pausa;

let estaPausado = false;
let sheetsError = false;

// FIX v3: Si hubo error en Google Sheets, marcar para fallback a PostgreSQL
if (data.error) {
  sheetsError = true;
  estaPausado = false;
  return [{ json: { ...data, estaPausado, sheetsError } }];
}

// Si no se encontro el numero en la hoja, NO esta pausado
if (!pausado && !fechaPausa && !data.row_number) {
  estaPausado = false;
  return [{ json: { ...data, estaPausado, sheetsError } }];
}

// FIX v3.1: Pausa expira despues de 14 dias (antes 7)
const DIAS_EXPIRACION_PAUSA = 14;

if (pausado === 'si' && fechaPausa) {
  const fechaPausaDate = new Date(fechaPausa);
  const ahora = new Date();
  const diasPasados = (ahora - fechaPausaDate) / (1000 * 60 * 60 * 24);

  if (diasPasados < DIAS_EXPIRACION_PAUSA) {
    estaPausado = true;
  }
  // Si pasaron mas de 14 dias, estaPausado queda false = bot atiende de nuevo
}

return [{ json: { ...data, estaPausado, sheetsError } }];

const body = $input.first().json.body;
const chatInput = body.chatInput || '';
const remoteJid = body.remoteJid || body.sessionId || '';
const senderName = body.pushName || 'Sin nombre';
const keyId = body.keyId || '';

const lines = chatInput.split('\n').filter(l => l.trim());

const textParts = [];
const audioMessageIds = [];
const imageMessageIds = [];

for (const line of lines) {
  if (line.startsWith('audioMessage|')) {
    audioMessageIds.push(line.split('|')[1]);
  } else if (line.startsWith('imageMessage|')) {
    imageMessageIds.push(line.split('|')[1]);
  } else {
    textParts.push(line);
  }
}

const combinedText = textParts.join('\n');
const hasAudio = audioMessageIds.length > 0;
const hasImage = imageMessageIds.length > 0;

return [{
  json: {
    remoteJid,
    senderName,
    combinedText,
    messageCount: lines.length,
    hasAudio,
    hasImage,
    audioMessageIds,
    imageMessageIds,
    imageMessageId: hasImage ? imageMessageIds[0] : '',
    audioMessageId: hasAudio ? audioMessageIds[0] : ''
  }
}];

