const imageIds = $('Info Multimedia').first().json.imageMessageIds || [];
if (imageIds.length === 0) return [{ json: { imageMessageId: '', empty: true } }];
return imageIds.map(id => ({ json: { imageMessageId: id } }));

const audioIds = $('Info Multimedia').first().json.audioMessageIds || [];
if (audioIds.length === 0) return [{ json: { audioMessageId: '', empty: true } }];
return audioIds.map(id => ({ json: { audioMessageId: id } }));

const execId = $execution.id;
const staticData = $getWorkflowStaticData('global');
const key = 'audio_' + execId;
if (!staticData[key]) staticData[key] = [];
const text = $input.first().json.text || '';
if (text) staticData[key].push(text);
return $input.all();

const execId = $execution.id;
const staticData = $getWorkflowStaticData('global');
const key = 'image_' + execId;
if (!staticData[key]) staticData[key] = [];

// FIX v3: Extraer texto correctamente del response de Anthropic Vision
// El nodo Anthropic devuelve {content: [{type:'text', text:'...'}]} 
// y antes se hacia .content que daba [object Object]
const raw = $input.first().json;
let text = '';
if (typeof raw.text === 'string' && raw.text.length > 0) {
  text = raw.text;
} else if (raw.content && Array.isArray(raw.content)) {
  text = raw.content.filter(c => c.type === 'text').map(c => c.text).join('\n');
} else if (typeof raw.content === 'string') {
  text = raw.content;
} else if (raw.output && typeof raw.output === 'string') {
  text = raw.output;
} else if (typeof raw === 'object') {
  text = JSON.stringify(raw);
}
if (text) staticData[key].push(text);
return $input.all();

// Evaluar resultado de fallback PostgreSQL CON expiracion de pausa
const pgResult = $input.first().json;
const chatInputData = $('Parsear chatInput').first().json;

const DIAS_EXPIRACION_PAUSA = 14;
let estaPausado = false;

// Si Postgres no devolvio filas, pgResult viene vacio = no esta pausado
if (pgResult && pgResult.remote_jid && pgResult.pausado === 'si') {
  if (pgResult.fecha_pausa) {
    const fechaPausa = new Date(pgResult.fecha_pausa);
    const ahora = new Date();
    const diasPasados = (ahora - fechaPausa) / (1000 * 60 * 60 * 24);
    estaPausado = diasPasados < DIAS_EXPIRACION_PAUSA;
  } else {
    estaPausado = true;
  }
}

return [{ json: { 
  ...chatInputData,
  estaPausado,
  fuentePausa: 'postgres_fallback'
}}];

// Buscar el @lid que corresponde al @s.whatsapp.net del contacto
const remoteJid = $('Juntar Resultados').first().json.remoteJid;

// findChats puede devolver como array en 1 item o como muchos items
const allItems = $input.all();
let chats = [];

if (allItems.length > 1) {
  chats = allItems.map(i => i.json);
} else {
  const first = allItems[0].json;
  if (Array.isArray(first)) {
    chats = first;
  } else {
    chats = [first];
  }
}

let lidJid = '';

for (const chat of chats) {
  const chatJid = chat.remoteJid || '';
  const alt = chat.lastMessage?.key?.remoteJidAlt || '';

  // Si el chat es @lid y su remoteJidAlt coincide con nuestro @s.whatsapp.net
  if (chatJid.endsWith('@lid') && alt === remoteJid) {
    lidJid = chatJid;
    break;
  }

  // Si el chat es @s.whatsapp.net y coincide, buscar el @lid en el alt
  if (chatJid === remoteJid && alt && alt.endsWith('@lid')) {
    lidJid = alt;
    break;
  }
}

return [{ json: {
  remoteJid: remoteJid,
  lidJid: lidJid,
  lidEncontrado: lidJid !== '',
  totalChatsRevisados: chats.length
}}];
